// crates/arest-kernel/src/ui_apps/mod.rs
//
// Slint apps for the AREST kernel (#429 Track SSS — first app;
// #510 / EPIC #496 merged the original two apps into UnifiedRepl).
//
// Each submodule wires `crate::system::with_state` queries to a
// component generated by `slint::include_modules!()` in
// `crate::arch::uefi::slint_backend`. The generated component types
// (e.g. `UnifiedRepl`, `AppShell`) are re-exported through that
// module's `slint::include_modules!()` site, so this submodule can
// reach them via `crate::arch::uefi::slint_backend::UnifiedRepl`
// without re-running the codegen.
//
// Platform note: the only target that wires Slint into a render path
// is `x86_64-unknown-uefi` (per Cargo.toml's slint = { ... } block
// being target-gated). The `mod ui_apps;` declaration in `main.rs` is
// therefore cfg-gated to that triple — this module's submodules
// transitively reach `crate::arch::uefi::slint_backend`, which is
// only present under the same cfg.
//
// Future apps add themselves here by sibling submodule. Each app's
// `build_app() -> ComponentHandle` constructor stays the canonical
// entry; #431 (Boot UI launcher) decides which app(s) actually go on
// screen at boot.

pub mod keyboard;
pub mod launcher;
pub mod registry;
// Cell-as-screen rendering helpers (#511, EPIC #496). Pure functions
// + small ADTs that classify a "current cell", select the best
// Component for it via #492's selection rules (kernel-internal port
// of `arest::command::select_component`, which is host-only), and
// project the cell's data into a list of human-readable lines for
// the typed-surface area. Consumed by `unified_repl`.
pub mod cell_renderer;
// Navigation actions as cells (#512, EPIC #496). Companion to
// `cell_renderer`: every screen IS a cell, every "navigate to X"
// affordance IS *also* a cell. The catalogue of legal next moves
// from a screen is computed by walking the FT graph (roles → joinable
// cells, derivations → consumed/produced cells, SM → next-state hop)
// rather than hand-listed per screen. Consumed by `unified_repl`'s
// right-pane navigation list.
pub mod navigation;
// SYSTEM calls as actions on the current screen (#513, EPIC #496).
// Third leg of the cell-graph HATEOAS triangle: `cell_renderer` says
// "what does this cell look like?", `navigation` says "what cells can
// I reach from here?", and `actions` says "what SYSTEM calls can I
// make from here?". Each action IS a cell of the implicit fact type
// `<current_cell> has system_action <Verb, Args>`; the catalogue is
// computed by walking the FT graph + the verb namespace rather than
// hand-listed per screen. Consumed by `unified_repl`'s right-pane
// action list.
pub mod actions;
// "You are here" breadcrumb + back/forward navigation history (#516,
// EPIC #496). Adds the navigation-history chrome to the unified REPL:
// a persistent breadcrumb across the top renders the path through the
// cell graph, classic browser-style back/forward stepping over the
// cell sequence, and bookmarks for quick return. The history itself
// IS a cell sequence — bookmarks are facts (a future task wires them
// into the cell graph), history is a ring buffer (#188 primitive).
pub mod breadcrumb;
// Unified REPL (#510, EPIC #496). Foundational structural merge of
// the previous `hateoas` (Track SSS #429) + `repl` (Track TTT #430)
// modules into a single panel — left pane drives the HATEOAS browse
// today's `hateoas` did, right pane drives the REPL prompt + scrollback
// today's `repl` did. Subsequent sub-tasks (#511 cell-as-screen, #512
// navigation actions, #513 SYSTEM-as-actions, …) layer on top.
pub mod unified_repl;
// Doom (#455 + #456 Track VVV). Gated behind `feature = "doom"`
// because the wasmi-instantiated jacobenget/doom.wasm v0.1.0 binary
// is GPL-2.0; the default kernel build ships AGPL-3.0-or-later only
// (#396). With the feature off, the app submodule is absent from the
// crate graph and `launcher.rs` skips the Doom button row.
#[cfg(feature = "doom")]
pub mod doom;
